#include <stdio.h>
#include <stdlib.h>
int cmp(const void *a, const void *b){return (*(int*)a)-(*(int*)b);} 
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d",&N,&M);
        int total=N+M;
        int *arr = (int*)malloc(total*sizeof(int));
        int i, k=0;
        for(i=0;i<N;i++) scanf("%d",&arr[k++]);
        for(i=0;i<M;i++) scanf("%d",&arr[k++]);
        // remove duplicates
        int uniq[30]; int u=0;
        for(i=0;i<k;i++){
            int j, found=0;
            for(j=0;j<u;j++) if(arr[i]==uniq[j]){found=1;break;}
            if(!found) uniq[u++]=arr[i];
        }
        qsort(uniq,u,sizeof(int),cmp);
        for(i=0;i<u;i++){
            if(i) printf(" ");
            printf("%d",uniq[i]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

